/// separating two constellations. Coordinates are in the B1875 equinox system (RA in hours,
/// Dec in degrees). Data from the Barbier reformulation of Delporte's boundaries,
/// same source as Stellarium's modern sky culture.
/// </summary>
public static class ConstellationEdges
{
    /// <summary>Edge type: Parallel = constant Dec, Meridian = constant RA, Straight = direct line.</summary>
    public enum EdgeType : byte { Parallel, Meridian, Straight }

